    "coordination.switch_project_aria": "Switch to a different project",
    "coordination.tl_bcf_topic": "BCF topic '{{name}}' ({{status}})",
    "coordination.tl_clash_completed": "Clash run '{{name}}' completed - {{total}} clashes",
