    "dwg_takeoff.offline_ready_tooltip_server": "Conversions run on your OpenConstructionERP server and are never sent to third parties.",
    "dwg_takeoff.processed_on_your_server": "Processed on your OpenConstructionERP server · never sent to third parties",
